// Pega os dados do node "Processar o retorno da IA"
const dadosIA = $('Processar o retorno da IA').item.json;

const legenda_twitter = dadosIA.legenda_twitter || '';
const legenda_whatsapp = dadosIA.legenda_whatsapp || '';

// Pega a URL da imagem do node anterior (assumindo que vem de um único node de geração)
const mergeData = $input.all();

// DEBUG: Vamos ver o que está vindo
console.log('Total de itens recebidos:', mergeData.length);
console.log('Estrutura do primeiro item:', JSON.stringify(mergeData[0]?.json, null, 2));

// Extrai a URL da imagem única
const imagem_url = mergeData[0]?.json?.imagem_url || '';

// DEBUG: Vamos ver a URL extraída
console.log('URL extraída:');
console.log('imagem_url:', imagem_url);

// Remove possíveis formatações markdown das legendas
const legendaTwitterLimpa = legenda_twitter.replace(/```|markdown/g, '').trim();
const legendaWhatsappLimpa = legenda_whatsapp.replace(/```|markdown/g, '').trim();

// Cria data formatada em português BR com timezone de São Paulo (GMT-3)
const agora = new Date();
const opcoes = {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
};

const dataFormatadaBR = new Intl.DateTimeFormat('pt-BR', opcoes).format(agora);
// Resultado: "10/12/2025, 21:47:48" - vamos remover a vírgula
const dataFormatada = dataFormatadaBR.replace(',', '');

// Retorna tudo formatado para inserir no Sheets
return [{
  json: {
    id_post: dadosIA.id_post,
    Titulo: dadosIA.Titulo,
    Legenda_Twitter: legendaTwitterLimpa,
    Legenda_WhatsApp: legendaWhatsappLimpa,
    Status: 'Aguardando Aprovação',
    imagem_url: imagem_url,
    data_criacao: dataFormatada
  }
}];

// --- Captura o retorno da IA ---
const items = $input.all();

if (!items || items.length === 0) {
  throw new Error("⚠️ Nenhum retorno da IA encontrado.");
}

let resultado = null;

for (const item of items) {
  let output = item.json.output || item.json.text || '';
  if (!output) continue;

  // Remove possíveis blocos Markdown
  output = output.replace(/```json|```/g, '').trim();

  try {
    resultado = JSON.parse(output);
    break; // Se parseou com sucesso, sai do loop
  } catch (err) {
    console.log('Erro ao parsear JSON:', err.message);
  }
}

if (!resultado) {
  throw new Error('❌ Não foi possível extrair JSON válido da resposta da IA');
}

// --- Valida estrutura ---
if (!resultado.texto_imagem || !resultado.query_unsplash || !resultado.legenda_twitter || !resultado.legenda_whatsapp) {
  throw new Error('❌ JSON retornado está incompleto. Campos obrigatórios: texto_imagem, query_unsplash, legenda_twitter, legenda_whatsapp');
}

// --- Retorna estrutura unificada e compatível ---
return [{
  json: {
    // Dados do post original
    id_post: $('Filtra Primeiro Post Aguardando').item.json.id_post,
    Titulo: $('Filtra Primeiro Post Aguardando').item.json.Titulo,

    // Estrutura completa da IA
    texto_imagem: resultado.texto_imagem,
    query_unsplash: resultado.query_unsplash,
    legenda_twitter: resultado.legenda_twitter,
    legenda_whatsapp: resultado.legenda_whatsapp
  }
}];

